import{_ as a,o as n,c as e,a2 as t}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse(`{"title":"What We'll Build","description":"A preview of the complete coding agent we will build throughout this tutorial track, including its architecture and capabilities.","frontmatter":{"title":"What We'll Build","description":"A preview of the complete coding agent we will build throughout this tutorial track, including its architecture and capabilities."},"headers":[],"relativePath":"learn/linear/01-what-is-a-coding-agent/13-what-well-build.md","filePath":"learn/linear/01-what-is-a-coding-agent/13-what-well-build.md"}`),l={name:"learn/linear/01-what-is-a-coding-agent/13-what-well-build.md"};function o(p,s,i,r,c,d){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="what-we-ll-build" tabindex="-1">What We&#39;ll Build <a class="header-anchor" href="#what-we-ll-build" aria-label="Permalink to &quot;What We&#39;ll Build&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>The high-level architecture of the coding agent we will implement step by step</li><li>The specific capabilities our agent will have: file operations, shell execution, search, and code editing</li><li>How each chapter of the tutorial maps to a component of the final system</li></ul></blockquote><h2 id="the-vision" tabindex="-1">The Vision <a class="header-anchor" href="#the-vision" aria-label="Permalink to &quot;The Vision&quot;">​</a></h2><p>Over the course of this tutorial track, you&#39;ll build a complete, working coding agent in Rust. Not a toy. Not a proof of concept. A real terminal-native agent that can read your codebase, write code, execute commands, run tests, and iterate on solutions — all orchestrated by a large language model.</p><p>By the end, you&#39;ll have a CLI tool that you type a natural language request into and watch as it reads files, thinks through the problem, writes a solution, tests it, and fixes any issues — the same fundamental experience that Claude Code, OpenCode, and Pi provide.</p><p>Let&#39;s walk through what this system looks like, starting from the outside and working our way in.</p><h2 id="the-user-experience" tabindex="-1">The User Experience <a class="header-anchor" href="#the-user-experience" aria-label="Permalink to &quot;The User Experience&quot;">​</a></h2><p>You&#39;ll launch the agent from your terminal in a project directory:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">$</span><span style="color:#A6E3A1;"> my-agent</span></span>
<span class="line"><span style="color:#94E2D5;">&gt;</span><span style="color:#CDD6F4;"> Fix the failing test in tests/integration/test_users.rs</span></span></code></pre></div><p>The agent begins working. You see streaming output as it thinks and acts:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Reading tests/integration/test_users.rs...</span></span>
<span class="line"><span>The test \`test_create_user_with_duplicate_email\` is failing because the</span></span>
<span class="line"><span>handler returns a 500 instead of a 409 Conflict.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Reading src/handlers/users.rs...</span></span>
<span class="line"><span>I see the issue. The \`create_user\` handler doesn&#39;t check for existing</span></span>
<span class="line"><span>users with the same email before inserting.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Writing src/handlers/users.rs...</span></span>
<span class="line"><span>Running cargo test...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 test failed: test_list_users_pagination - the pagination offset is</span></span>
<span class="line"><span>now off by one because of the early return I added.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Writing src/handlers/users.rs...</span></span>
<span class="line"><span>Running cargo test...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All 23 tests passing. Here&#39;s what I changed:</span></span>
<span class="line"><span>- Added a duplicate email check in \`create_user\` that returns 409</span></span>
<span class="line"><span>- Fixed the pagination query to account for the new early return path</span></span></code></pre></div><p>This is the experience we&#39;re building toward. The agent reads, thinks, acts, observes, and iterates — just like the production agents we studied.</p><h2 id="the-architecture" tabindex="-1">The Architecture <a class="header-anchor" href="#the-architecture" aria-label="Permalink to &quot;The Architecture&quot;">​</a></h2><p>Our agent follows the five-component architecture we extracted from production agents:</p><h3 id="_1-the-repl-interface" tabindex="-1">1. The REPL Interface <a class="header-anchor" href="#_1-the-repl-interface" aria-label="Permalink to &quot;1. The REPL Interface&quot;">​</a></h3><p>The user-facing layer is a Read-Eval-Print Loop — a terminal interface where you type requests and see streaming responses. We&#39;ll build this with Rust&#39;s standard I/O initially, then upgrade to a richer terminal UI with Ratatui for features like syntax highlighting, scrollable history, and status indicators.</p><p>The REPL handles:</p><ul><li>Reading user input (with line editing and history).</li><li>Rendering streaming text from the LLM.</li><li>Displaying tool call notifications and results.</li><li>Showing progress indicators during long operations.</li></ul><h3 id="_2-the-llm-client" tabindex="-1">2. The LLM Client <a class="header-anchor" href="#_2-the-llm-client" aria-label="Permalink to &quot;2. The LLM Client&quot;">​</a></h3><p>The LLM client communicates with the Anthropic API (Claude). It constructs messages in the format the API expects, sends them over HTTPS, and parses the streaming response. This is the reasoning engine of the agent — everything the agent &quot;thinks&quot; happens through this client.</p><p>The client handles:</p><ul><li>Message construction (system prompt, conversation history, tool definitions).</li><li>HTTP request management with proper headers and authentication.</li><li>Server-sent event (SSE) stream parsing for real-time output.</li><li>Error handling for rate limits, network failures, and API errors.</li></ul><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// The core message types our client works with</span></span>
<span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    role</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ContentBlock</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> Role</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    User</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Assistant</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> ContentBlock</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Text</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolUse</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        name</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        input</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;"> serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ToolResult</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        tool_use_id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="_3-the-agentic-loop" tabindex="-1">3. The Agentic Loop <a class="header-anchor" href="#_3-the-agentic-loop" aria-label="Permalink to &quot;3. The Agentic Loop&quot;">​</a></h3><p>The agentic loop is the orchestrator. It sits between the REPL, the LLM client, and the tool system, driving the perceive-reason-act cycle:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Simplified view of our agentic loop</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> agent_loop</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;">    client</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">LlmClient</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    tools</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">ToolDispatcher</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    messages</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">()</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">send_message</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Display text content to the user</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        display_text</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Extract tool calls</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> tool_calls </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> extract_tool_calls</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> tool_calls</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">is_empty</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            break</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;"> // Model is done — no more tool calls</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Execute each tool and collect results</span></span>
<span class="line"><span style="color:#CBA6F7;">        for</span><span style="color:#CDD6F4;"> call </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> tool_calls </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tools</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">dispatch</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">            messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">tool_result_message</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Add the assistant&#39;s response to history, then loop</span></span>
<span class="line"><span style="color:#CDD6F4;">        messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">assistant_message</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This simple loop structure drives the entire agent. The sophistication comes from the tools it dispatches and the model that decides what to do.</p><h3 id="_4-the-tool-system" tabindex="-1">4. The Tool System <a class="header-anchor" href="#_4-the-tool-system" aria-label="Permalink to &quot;4. The Tool System&quot;">​</a></h3><p>The tool system is the richest part of our architecture. We&#39;ll implement the tools that give the agent its capabilities:</p><p><strong>File Read (<code>read_file</code>):</strong> Reads the contents of a file by path, with optional line range selection. This is the agent&#39;s primary perception tool — how it sees your code.</p><p><strong>File Write (<code>write_file</code>):</strong> Creates or modifies files. We&#39;ll implement both full-file replacement (simpler) and diff-based editing (more precise). The agent uses this to make changes to your codebase.</p><p><strong>Shell Execute (<code>shell_exec</code>):</strong> Runs a command in the user&#39;s shell and captures stdout, stderr, and the exit code. This is how the agent runs tests, builds projects, checks git status, and performs any operation that requires a command.</p><p><strong>Search (<code>search</code>):</strong> Searches for patterns across files in the project, similar to <code>grep</code> or <code>ripgrep</code>. This lets the agent find relevant code without reading every file — crucial for navigating large codebases efficiently.</p><p><strong>List Directory (<code>list_dir</code>):</strong> Lists the contents of a directory with file types and sizes. This gives the agent a map of the project structure.</p><p>Each tool implements a common trait:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">async_trait</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">trait</span><span style="color:#F9E2AF;font-style:italic;"> Tool</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Sync</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> name</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> description</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> parameters_schema</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> execute</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> params</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ToolResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>This trait-based tool design is analogous to defining an abstract base class in Python:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> abc </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> ABC</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> abstractmethod</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> Tool</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ABC</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @abstractmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> name</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> ...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @abstractmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> description</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> ...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @abstractmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> parameters_schema</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> dict</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> ...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    @abstractmethod</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> def</span><span style="color:#89B4FA;font-style:italic;"> execute</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> params</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> dict</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> ToolResult</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> ...</span></span></code></pre></div><p>The Rust version provides stronger guarantees — if you forget to implement a method, the compiler tells you. The <code>Send + Sync</code> bounds ensure tools are safe to use across async tasks.</p></div><h3 id="_5-context-management" tabindex="-1">5. Context Management <a class="header-anchor" href="#_5-context-management" aria-label="Permalink to &quot;5. Context Management&quot;">​</a></h3><p>As the conversation grows, we need to manage the context window. Our agent will implement:</p><ul><li><strong>Token counting:</strong> Estimating the token count of the current conversation to track context usage.</li><li><strong>Context compaction:</strong> When the conversation exceeds a threshold, summarizing earlier messages to free up space.</li><li><strong>Smart truncation:</strong> Handling oversized tool results (like the output of <code>cat</code> on a huge file) by truncating with a notice.</li></ul><h3 id="supporting-components" tabindex="-1">Supporting Components <a class="header-anchor" href="#supporting-components" aria-label="Permalink to &quot;Supporting Components&quot;">​</a></h3><p>Beyond the five core components, we&#39;ll also build:</p><ul><li><strong>Configuration system:</strong> TOML-based config for API keys, model selection, and preferences.</li><li><strong>Permission system:</strong> Tiered permissions for read, write, and execute operations.</li><li><strong>Error handling infrastructure:</strong> Custom error types with the <code>thiserror</code> crate for clear, recoverable error paths.</li><li><strong>Logging:</strong> Structured logging for debugging and session analysis.</li></ul><h2 id="the-chapter-roadmap" tabindex="-1">The Chapter Roadmap <a class="header-anchor" href="#the-chapter-roadmap" aria-label="Permalink to &quot;The Chapter Roadmap&quot;">​</a></h2><p>Here&#39;s how the tutorial maps to the architecture:</p><table tabindex="0"><thead><tr><th>Chapter</th><th>Topic</th><th>What You Build</th></tr></thead><tbody><tr><td>1</td><td>What Is a Coding Agent?</td><td>Mental model and architectural blueprint (this chapter)</td></tr><tr><td>2</td><td>Rust Fundamentals for Agents</td><td>Rust basics tailored for agent development</td></tr><tr><td>3</td><td>LLM Integration</td><td>HTTP client, API calls, streaming response parsing</td></tr><tr><td>4</td><td>The Agentic Loop</td><td>Core loop, message types, turn management</td></tr><tr><td>5</td><td>File Operations</td><td>Read, write, and list directory tools</td></tr><tr><td>6</td><td>Shell Execution</td><td>Process spawning, output capture, timeouts</td></tr><tr><td>7</td><td>Code Search</td><td>Pattern matching across files, search tool</td></tr><tr><td>8</td><td>Tool Dispatch</td><td>Trait-based dispatch, tool registry, parameter validation</td></tr><tr><td>9</td><td>Context Management</td><td>Token counting, compaction, smart truncation</td></tr><tr><td>10</td><td>Streaming UI</td><td>Ratatui-based terminal interface with streaming</td></tr><tr><td>11</td><td>Conversation Memory</td><td>Session persistence, conversation history</td></tr><tr><td>12</td><td>Permissions and Safety</td><td>Permission system, command classification, approval flow</td></tr><tr><td>13</td><td>Testing Your Agent</td><td>Integration tests, mock LLM, tool testing</td></tr><tr><td>14</td><td>Advanced Patterns</td><td>Multi-tool calls, error recovery, planning</td></tr></tbody></table><p>Each chapter builds on the previous ones. By Chapter 4, you&#39;ll have a working (if limited) agent that can chat. By Chapter 6, it can read files, write code, and run commands. By Chapter 10, it has a polished terminal interface. By Chapter 14, it handles edge cases and advanced scenarios that make it genuinely useful for real work.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>The progression of our build mirrors how production agents were developed. Claude Code didn&#39;t ship with every feature on day one — it started as a basic REPL with API connectivity, then added tools, then streaming, then permissions, then polish. OpenCode&#39;s git history shows the same pattern: core loop first, tools second, UI third, refinements last. This layered approach isn&#39;t just pedagogically convenient — it&#39;s how real agents are built.</p></div><h2 id="what-we-won-t-build" tabindex="-1">What We Won&#39;t Build <a class="header-anchor" href="#what-we-won-t-build" aria-label="Permalink to &quot;What We Won&#39;t Build&quot;">​</a></h2><p>Setting expectations is as important as setting ambitions. Here&#39;s what falls outside our scope:</p><ul><li><strong>Multi-model support.</strong> We&#39;ll target the Anthropic API specifically. Adding other providers is a great exercise once you have the core working, but starting provider-agnostic adds complexity without teaching new concepts.</li><li><strong>Web browsing.</strong> Some agents can open web pages and read documentation. We&#39;ll focus on filesystem and shell tools.</li><li><strong>Visual output.</strong> Image generation, diagram rendering, and rich media are out of scope. Our agent is text-focused.</li><li><strong>Multi-agent orchestration.</strong> Coordinating multiple agents is fascinating but requires a solid single-agent foundation first.</li></ul><p>These aren&#39;t shortcomings — they&#39;re scope decisions. Each of these features could be added to the system we build, and you&#39;ll have the architectural understanding to do so. The foundation is what matters.</p><h2 id="the-end-goal" tabindex="-1">The End Goal <a class="header-anchor" href="#the-end-goal" aria-label="Permalink to &quot;The End Goal&quot;">​</a></h2><p>When you finish this tutorial, you&#39;ll have:</p><ol><li><strong>A working coding agent</strong> — a real CLI tool that you can use for everyday development tasks.</li><li><strong>Deep architectural understanding</strong> — knowledge of every component in the system and how they interact.</li><li><strong>A platform for experimentation</strong> — a codebase you own completely, ready for customization and extension.</li><li><strong>Rust proficiency</strong> — practical experience with async Rust, traits, enums, error handling, and systems programming.</li></ol><p>You won&#39;t just understand how coding agents work. You&#39;ll have built one with your own hands.</p><p>Let&#39;s get started.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Our agent follows the five-component architecture shared by all production agents: REPL interface, LLM client, agentic loop, tool system, and context management.</li><li>The tool system provides five core capabilities: file reading, file writing, shell execution, code search, and directory listing — sufficient for a wide range of real-world development tasks.</li><li>The tutorial follows a layered build progression: core loop first, then tools, then UI, then safety, then polish — the same order that production agents were developed in.</li><li>The agent targets the Anthropic API specifically, keeping the LLM integration focused while the architecture remains general enough to support other providers later.</li><li>By the end, you&#39;ll have a working CLI agent, deep architectural knowledge, a customization platform, and practical Rust experience — four concrete outcomes from a single project.</li></ul>`,59)])])}const u=a(l,[["render",o]]);export{h as __pageData,u as default};
